// Parse JSON events (GET /v1/sessions/{id}/events), non-streaming
const resp = $input.first().json;
const events = Array.isArray(resp) ? resp : (resp.data || resp.events || []);
if (!events.length) throw new Error('No events in session response');

// Trouve le dernier event type=='agent.message' (ou 'agent') avec content text
const agentMessages = events.filter(e => {
  const t = e.type || '';
  return (t === 'agent' || t.startsWith('agent.message') || t === 'agent.turn_completed') && Array.isArray(e.content);
});
const lastAgent = agentMessages[agentMessages.length - 1] || events[events.length - 1];
if (!lastAgent || !Array.isArray(lastAgent.content)) {
  throw new Error('No agent message with content found. Last event type: ' + (events[events.length-1]||{}).type);
}

const textBlock = lastAgent.content.find(c => (c.type === 'text' || c.type === 'output_text') && c.text);
if (!textBlock) throw new Error('Agent message has no text block');

// Extraire le JSON array (même si entouré de markdown fences)
let jsonText = textBlock.text.trim();
const match = jsonText.match(/\[[\s\S]*\]/);
if (!match) throw new Error('No JSON array in agent output. Raw: ' + jsonText.slice(0,500));

const prospects = JSON.parse(match[0]);
if (!Array.isArray(prospects)) throw new Error('Parsed value is not an array');

return prospects.map(p => ({
  json: {
    ...p,
    agent_session_id: $('Create Agent Session').item.json.id,
    source: 'deep_researcher',
    raw_agent_output: p
  }
}));

// Filtre: garder seulement les prospects avec email valide et score >= 60
const items = $input.all();
return items.filter(i => {
  const p = i.json;
  return p.email_contact && /@/.test(p.email_contact) && (p.score_ia || 0) >= 60;
});

// Parse output Claude Haiku (JSON {subject, body})
const items = $input.all();
return items.map((i, idx) => {
  const prospect = $('Filter Top Prospects').all()[idx].json;
  let parsed = { subject: '', body: '' };
  try {
    const text = (i.json.content || i.json.text || i.json.output || '').trim();
    const match = text.match(/\{[\s\S]*\}/);
    if (match) parsed = JSON.parse(match[0]);
  } catch (e) {}
  return {
    json: {
      ...prospect,
      email_subject: parsed.subject || `Un regard sur le digital de ${prospect.nom_etablissement}`,
      email_body: parsed.body || ''
    }
  };
});

// Agrège stats pour Telegram
const contacted = $input.all().length;
const total = $('Parse Prospects JSON').all().length;
return [{ json: { total_prospects: total, contacted, date: new Date().toISOString().slice(0,10) } }];
